              </>
            )}
          </DropdownMenuContent>
        </DropdownMenu>

        {onAddRow && (
          <Button
            variant="outline"
            size="sm"
            onClick={onAddRow}
            className="h-9 gap-1 shadow-sm"
          >
            <PlusIcon className="size-3.5" />
